function initDrawGrid(){let host=$('#point-grid'); if(host&&!host.dataset.ready)makeGrid()}
async function load(){initDrawGrid(); MANIFEST=await fetch('data/manifest.json').then(r=>r.json()); let sum=$('#summary'); if(sum){sum.innerHTML=''; sum.hidden=true} EDGE_DICT=unpackDict(MANIFEST.edgeDictPacked,MANIFEST.edgeDict); MULT_DICT=unpackDict(MANIFEST.multDictPacked,MANIFEST.multDict); let loaded=0; for(const ch of MANIFEST.metaChunks){let raw=await fetch('data/'+ch.file).then(r=>MANIFEST.metaEncoding==='uvarintBinV2'?r.arrayBuffer():((MANIFEST.metaEncoding==='base36csvtxt'||MANIFEST.metaEncoding==='uvarintB64v1')?r.text():r.json())); let arr=decodeMetaChunk(raw); for(const row of arr){if(MANIFEST.metaPacked){row[MIDX.edge]=EDGE_DICT[row[MIDX.edge]]; row[MIDX.mult]=MULT_DICT[row[MIDX.mult]]} META.push(row); BY_ID.set(row[MIDX.id],row); let sig=[row[MIDX.Vol],row[MIDX.V],row[MIDX.B],row[MIDX.I],row[MIDX.edge],row[MIDX.content],row[MIDX.mult]].join('|'); if(!BUCKET.has(sig))BUCKET.set(sig,[]); BUCKET.get(sig).push(row)} loaded+=arr.length; $('#load-status').textContent=`Loaded ${loaded.toLocaleString()} metadata rows...`; await new Promise(r=>setTimeout(r,0)) } $('#load-status').textContent=`Ready: ${META.length.toLocaleString()} searchable records.`; renderMath(document.body); $('#search-status').textContent='Ready. Submit the empty form to display all records.'}
async function fetchRecord(row){if(row&&row.__virtual)return {rid:row[MIDX.id],v:clonePoints(row.__vertices),src:['drawn polygon; no database record'],srcCount:0,virtual:true}; let cno=row[MIDX.cno], off=row[MIDX.off], ch=MANIFEST.dataChunks[cno-1], f=ch.file; if(!DATA_CACHE.has(f)){if(MANIFEST.dataPacked==='flatSourceTxtV2'){let txt=await fetch('data/'+f).then(r=>r.text()); DATA_CACHE.set(f,txt.trim()?txt.trim().split('\n'):[])}else if(MANIFEST.dataPacked==='flatSourceVarB64V3'){let txt=await fetch('data/'+f).then(r=>r.text()); DATA_CACHE.set(f,decodeDataChunkVar(txt))}else if(MANIFEST.dataPacked==='flatSourceVarBinV4'){let buf=await fetch('data/'+f).then(r=>r.arrayBuffer()); DATA_CACHE.set(f,decodeDataChunkVar(buf))}else{DATA_CACHE.set(f, await fetch('data/'+f).then(r=>r.json()))}} let raw=DATA_CACHE.get(f)[off], rec=MANIFEST.dataPacked==='flatSourceTxtV2'?decodePackedDataLine(raw):raw; if(MANIFEST.dataPacked==='flatSourceV1'||MANIFEST.dataPacked==='flatSourceTxtV2'||MANIFEST.dataPacked==='flatSourceVarB64V3'||MANIFEST.dataPacked==='flatSourceVarBinV4')return {rid:row[MIDX.id],v:unflatVertices(rec[0]),src:decodeSource(rec[1],row[MIDX.src]),srcCount:1}; return {rid:rec[0],v:rec[1],src:rec[2]||[],srcCount:rec[3]||((rec[2]||[]).length)}}
function formValues(form){return Object.fromEntries(new FormData(form).entries())}
function filterRow(r,F){if(F.id){let q=parseInt(F.id.replace(/\D/g,'')); if(r[MIDX.id]!==q)return false} if(F.src&&String(r[MIDX.src])!==F.src)return false; if(!cmp(r[MIDX.Vol],F.volOp,F.vol))return false; if(!cmp(r[MIDX.V],F.vOp,F.V))return false; if(!cmp(r[MIDX.B],F.bOp,F.B))return false; if(!cmp(r[MIDX.I],F.iOp,F.I))return false; if(!cmp(r[MIDX.N],F.nOp,F.N))return false; if(!cmp(r[MIDX.lw],F.lwOp,F.lw))return false; if(!F._skipBox&&!cmp(r[MIDX.box],F.boxOp,F.box))return false; if(!cmp(r[MIDX.content],F.contentOp,F.content))return false; if(!cmp(r[MIDX.prim],F.primOp,F.prim))return false; if(!cmp(r[MIDX.maxE],F.maxEdgeOp,F.maxEdge))return false; if(!cmp(r[MIDX.minE],F.minEdgeOp,F.minEdge))return false; if(!cmp(r[MIDX.V]-2,F.rhoOp,F.rho))return false; if(!cmp(r[MIDX.I]>0?1:(r[MIDX.B]>3?2:3),F.codegOp,F.codeg))return false; if(F.edge&&r[MIDX.edge]!==F.edge.replace(/\s+/g,''))return false; if(F.mult&&r[MIDX.mult]!==F.mult.replace(/\s+/g,''))return false; if(F.smooth!==''&&String(r[MIDX.smooth])!==F.smooth)return false; if(F.centSym!==''&&String(r[MIDX.cent])!==F.centSym)return false; return true}
async function search(ev){ev&&ev.preventDefault(); renderStop=false; let F=formValues($('#search-form')), lim=F.limit===''?Infinity:Math.max(1,+F.limit||Infinity), needsExactBox=F.box!==''; if(needsExactBox)F._skipBox=true; let hits=[]; let t0=performance.now(), checked=0; for(const r of META){if(!filterRow(r,F))continue; if(needsExactBox){let rec=await fetchRecord(r), exactBox=stats(optDisplay(rec.v).v).boxSq; checked++; if(!cmp(exactBox,F.boxOp,F.box))continue; if(checked%250===0){$('#search-status').textContent=`Exact minimum-square checked ${checked.toLocaleString()} candidate rows...`; await new Promise(x=>setTimeout(x,0))}} hits.push(r); if(hits.length>=lim)break} $('#search-status').textContent=`Filtered ${META.length.toLocaleString()} rows${needsExactBox?` with ${checked.toLocaleString()} exact square checks`:''} in ${(performance.now()-t0).toFixed(0)} ms. Merging AGL2Z-equivalent records...`; $('#results').innerHTML=''; let grouped=await groupRowsByPolygon(hits); $('#result-count').textContent=grouped.length.toLocaleString(); await renderResults(grouped,$('#results'),{alreadyGrouped:true,autoOpen:true}); $('#search-status').textContent=`${grouped.length.toLocaleString()} merged result${grouped.length===1?'':'s'} rendered from ${hits.length.toLocaleString()} matching record${hits.length===1?'':'s'}.`}
async function groupRowsByPolygon(rows){let groups=[], byKey=new Map(), bySig=new Map(), groupPolys=[]; for(let i=0;i<rows.length&&!renderStop;i++){let r=rows[i], rec=await fetchRecord(r), st=stats(rec.v), sig=signatureFromStats(st), key=optKey(rec.v), g=byKey.get(key); if(!g){let idx=null; for(const gi of bySig.get(sig)||[]){if(aglEquivalent(rec.v,groupPolys[gi])){idx=gi;break}} if(idx===null){r.equivRows=[]; r.equivKey=key; idx=groups.length; groups.push(r); groupPolys.push(rec.v); if(!bySig.has(sig))bySig.set(sig,[]); bySig.get(sig).push(idx)} g=groups[idx]; byKey.set(key,g)} g.equivRows.push(r); if(i&&i%250===0){$('#search-status')&&($('#search-status').textContent=`Merging equivalent polygons with exact AGL2Z fallback: ${i.toLocaleString()}/${rows.length.toLocaleString()} records...`); await pause()}} return groups}
function recordLabel(r){return r&&r.__virtual?(r.__virtualTitle||'Drawn polygon'):id(r[MIDX.id])}
function groupLabel(r){if(r&&r.__virtual)return recordLabel(r); let g=r.equivRows||[r]; return g.length>1?`${id(r[MIDX.id])} + ${g.length-1} equivalent record(s)`:id(r[MIDX.id])}
function groupSources(r){if(r&&r.__virtual)return 'drawn'; let g=r.equivRows||[r], labs=[...new Set(g.map(x=>srcName(x[MIDX.src])))]; return labs.join(', ')}
async function renderResults(rows,container,opts={}){container.innerHTML=''; let grouped=opts.alreadyGrouped?rows:await groupRowsByPolygon(rows), batch=300; for(let i=0;i<grouped.length&&!renderStop;i+=batch){let frag=document.createDocumentFragment(); for(const r of grouped.slice(i,i+batch))frag.appendChild(resultElement(r)); container.appendChild(frag); await pause()} if(!grouped.length)container.innerHTML='<p class="empty">No matching records.</p>'; if(opts.autoOpen&&grouped.length===1){let btn=container.querySelector('[data-act="open"]'); if(btn)btn.click()}}
function resultElement(r,originHint=null){let el=document.createElement('div'); el.className='result'; let eq=r.equivRows?.length>1?`<span class="chip">merged ${r.equivRows.length}</span>`:''; el.innerHTML=`<div class="result-main"><div><div class="result-title">${groupLabel(r)} <span class="chip">${groupSources(r)}</span>${eq}</div><div class="chips"><span class="chip">Vol ${r[MIDX.Vol]}</span><span class="chip">V ${r[MIDX.V]}</span><span class="chip">B ${r[MIDX.B]}</span><span class="chip">I ${r[MIDX.I]}</span><span class="chip">N ${r[MIDX.N]}</span><span class="chip">lw ${r[MIDX.lw]}</span><span class="chip">edge [${r[MIDX.edge]}]</span></div></div><div class="result-actions"><button type="button" data-act="open" class="open-record-btn">Open</button><button type="button" data-act="download">Download</button></div></div><div class="detail-slot" hidden></div>`; let slot=el.querySelector('.detail-slot'), openBtn=el.querySelector('[data-act="open"]'); openBtn.onclick=async()=>{if(!slot.hidden){slot.hidden=true;slot.innerHTML='';openBtn.textContent='Open';openBtn.classList.remove('opened');return} slot.hidden=false; openBtn.textContent='Close'; openBtn.classList.add('opened'); slot.innerHTML='<p class="empty">Loading record...</p>'; await openRecord(r,slot,originHint)}; el.querySelector('[data-act="download"]').onclick=()=>downloadRecordData(r); return el}
function transformDisplay(v){let base=optDisplay(v).v; let b=bbox(base), W=b.maxX-b.minX, H=b.maxY-b.minY; let P=base.map(p=>[p[0]-b.minX,p[1]-b.minY]); for(let k=0;k<((viewState.rot%4)+4)%4;k++){P=P.map(p=>[p[1],W-p[0]]); [W,H]=[H,W]} if(viewState.fx)P=P.map(p=>[W-p[0],p[1]]); if(viewState.fy)P=P.map(p=>[p[0],H-p[1]]); return cyc(P)}
async function openRecord(row,slot,originHint=null){try{let rec=await fetchRecord(row); currentOpen={row,rec,slot}; selectedOrigin=originHint; viewState={rot:0,fx:false,fy:false}; renderRecord()}catch(e){console.error('openRecord failed',e); if(slot)slot.innerHTML=`<div class="card error-card"><h3>Could not render record</h3><p class="empty">${e&&e.message?e.message:e}</p><pre class="code-box">${String(e&&e.stack?e.stack:e).replace(/[<>&]/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]))}</pre></div>`}}
function renderRecord(){let {row,rec,slot}=currentOpen; let v=transformDisplay(rec.v), s=stats(v), P=latticePoints(v); if(!selectedOrigin||!P.inn.some(p=>p[0]===selectedOrigin[0]&&p[1]===selectedOrigin[1]))selectedOrigin=P.inn[0]||null; let verts=new Set(v.map(p=>p.join(','))), boundaryNonVerts=P.bd.filter(p=>!verts.has(p.join(','))); let G=[{P:boundaryNonVerts,c:'boundary',r:3,label:'boundary lattice point'},{P:P.inn,c:'interior',r:4,label:'interior lattice point'},{P:v,c:'vertex',r:5,label:'vertex'}]; if(selectedOrigin)G.push({P:[selectedOrigin],c:'origin',r:7,label:'selected origin'}); let cent=centroidData(v,P); let CG=[{P:[cent.area.point],c:'centA',r:6,label:'area centroid'},{P:[cent.all.point],c:'centL',r:6,label:'lattice centroid'},{P:[cent.boundary.point],c:'centB',r:6,label:'boundary centroid'}]; if(cent.interior)CG.push({P:[cent.interior.point],c:'centI',r:6,label:'interior centroid'}); slot.innerHTML=`<div class="record-grid"><div class="wide-figures"><div class="card"><h3>${recordLabel(row)}: minimum-square display</h3><div class="toggle-row"><button id="rotL">↺ 90°</button><button id="rotR">↻ 90°</button><button id="flipX">left/right flip</button><button id="flipY">up/down flip</button>${copyButton(v)}</div><div class="figure-box" id="poly-figure">${svgPolygon(v,G,{large:true})}</div><p class="subtle">Vertices are red, boundary lattice points blue, interior lattice points green, and the selected origin is black. All invariants depending on a pointed origin use the black interior point selected here. If no external choice is provided, the first interior lattice point is selected automatically.</p><div class="point-buttons">${P.inn.map(p=>`<button data-p="${p.join(',')}" class="${selectedOrigin&&selectedOrigin[0]===p[0]&&selectedOrigin[1]===p[1]?'active':''}">(${p[0]},${p[1]})</button>`).join('')||'<span class="subtle">No interior lattice points.</span>'}</div></div><div class="card"><h3>Centroids</h3><div class="toggle-row">${copyButton(v)}</div><div class="figure-box">${svgPolygon(v,CG,{large:false})}</div><div class="coords">${centroidText(cent)}</div></div></div><div>${basicSection(s,row,rec,P)}${symmetrySection(s,P)}${ehrhartSection(s)}${toricSection(s,v,P)}${algebraicSection(s)}${minkowskiSection(s,P)}</div><div>${fanSection(s,v)}${pointedSection(s,v)}${primitivePolygonSection(s,v)}${dualPolygonSection(s,v)}${neighborSection()}</div></div>`; slot.querySelector('#rotL').onclick=()=>{viewState.rot--;selectedOrigin=null;renderRecord()}; slot.querySelector('#rotR').onclick=()=>{viewState.rot++;selectedOrigin=null;renderRecord()}; slot.querySelector('#flipX').onclick=()=>{viewState.fx=!viewState.fx;selectedOrigin=null;renderRecord()}; slot.querySelector('#flipY').onclick=()=>{viewState.fy=!viewState.fy;selectedOrigin=null;renderRecord()}; slot.querySelectorAll('#poly-figure .interior,.point-buttons button[data-p]').forEach(el=>el.onclick=()=>{selectedOrigin=el.dataset.p.split(',').map(Number);renderRecord()}); let eh=slot.querySelector('#ehrhart-order'); if(eh)eh.onchange=()=>updateEhrhartSeries(s,slot); let nb=slot.querySelector('#compute-neighbors'); if(nb)nb.onclick=()=>computeNeighbors(v,slot); attachBlowupControls(v,slot); let bu=slot.querySelector('#compute-blowup'); if(bu)bu.onclick=()=>computeBlowup(v,slot); let bd=slot.querySelector('#compute-blowdown'); if(bd)bd.onclick=()=>computeBlowdownDAG(v,slot); let per=slot.querySelector('#compute-period'); if(per)per.onclick=()=>computeMirrorPeriod(v,slot); let pf=slot.querySelector('#compute-pf'); if(pf)pf.onclick=()=>computePicardFuchsPackage(v,slot); let stopPf=slot.querySelector('#stop-pf'); if(stopPf)stopPf.onclick=()=>{if(PF_CANCEL)PF_CANCEL.cancelled=true}; let mk=slot.querySelector('#compute-minkowski'); if(mk)mk.onclick=()=>computeMinkowskiDecompositions(v,slot); attachCopyButtons(slot); renderMath(slot); setTimeout(()=>{if(currentOpen&&currentOpen.slot===slot){computeNeighbors(v,slot); computeAdjointMatches(v,slot); computePrimitiveSearch(v,slot); computeDualSearch(v,slot); computeMinkowskiDecompositions(v,slot)}},0)}
function svgPolygon(v,groups=[],opts={}){let all=v.concat(groups.flatMap(g=>g.P)); let b=bbox(all), pad=opts.large?36:28, maxW=opts.large?760:520, maxH=opts.large?520:360; let sx=maxW/Math.max(1,b.maxX-b.minX+1), sy=maxH/Math.max(1,b.maxY-b.minY+1), sc=Math.min(sx,sy,48); let W=(b.maxX-b.minX)*sc+2*pad, H=(b.maxY-b.minY)*sc+2*pad; let X=p=>pad+(p[0]-b.minX)*sc, Y=p=>H-pad-(p[1]-b.minY)*sc; let s=`<svg width="100%" height="${H}" viewBox="0 0 ${W} ${H}" role="img">`; for(let x=Math.floor(b.minX);x<=Math.ceil(b.maxX);x++)s+=`<line class="${x===0?'axisline':'gridline'}" x1="${X([x,b.minY])}" y1="${Y([x,b.minY])}" x2="${X([x,b.maxY])}" y2="${Y([x,b.maxY])}"/>`; for(let y=Math.floor(b.minY);y<=Math.ceil(b.maxY);y++)s+=`<line class="${y===0?'axisline':'gridline'}" x1="${X([b.minX,y])}" y1="${Y([b.minX,y])}" x2="${X([b.maxX,y])}" y2="${Y([b.maxX,y])}"/>`; s+=`<polygon class="poly" points="${v.map(p=>X(p)+','+Y(p)).join(' ')}"/>`; for(const g of groups)for(const p of g.P){s+=`<circle class="${g.c}" cx="${X(p)}" cy="${Y(p)}" r="${g.r||4}" data-p="${p[0]},${p[1]}"><title>${g.label||g.c}: (${fmtPoint(p)})</title></circle>`} return s+'</svg>'}
function fmtPoint(p){return `${numFmt(p[0])}, ${numFmt(p[1])}`}
function numFmt(x){return Number.isInteger(x)?String(x):String(Math.round(x*10000)/10000)}
function frac(n,d=1){if(d<0){n=-n;d=-d} if(n===0)return '0'; let g=gcd(n,d); n/=g; d/=g; return d===1?String(n):`${n}/${d}`}
function fracObj(n,d=1){if(d<0){n=-n;d=-d} if(n===0)return{n:0,d:1}; let g=gcd(n,d); return{n:n/g,d:d/g}}
function fracObjFromNumber(x){if(Number.isInteger(x))return fracObj(x,1); let s=fracFromNumber(x); if(s.includes('/')){let [n,d]=s.split('/').map(Number); return fracObj(n,d)} return fracObj(Number(s)||0,1)}
function fracAdd(a,b){return fracObj(a.n*b.d+b.n*a.d,a.d*b.d)}
function fracMulInt(a,k){return fracObj(a.n*k,a.d)}
function fracText(a){return frac(a.n,a.d)}
function fracLatex(a){return a.d===1?String(a.n):`\\frac{${a.n}}{${a.d}}`}
function fracFromNumber(x){if(!Number.isFinite(x))return String(x); if(Math.abs(x-Math.round(x))<1e-10)return String(Math.round(x)); let sign=x<0?'-':''; x=Math.abs(x); let h1=1,h0=0,k1=0,k0=1,b=x; for(let i=0;i<20;i++){let a=Math.floor(b), h=a*h1+h0, k=a*k1+k0; if(k>10000)break; if(Math.abs(h/k-x)<1e-10)return sign+(k===1?String(h):`${h}/${k}`); h0=h1;h1=h;k0=k1;k1=k; b=1/(b-a)} let d=10000,n=Math.round(x*d),g=gcd(n,d); return sign+(d/g===1?String(n/g):`${n/g}/${d/g}`)}
function avgFrac(points){let sx=0,sy=0; for(const p of points){sx+=p[0];sy+=p[1]} return {point:[sx/points.length,sy/points.length],text:`(${frac(sx,points.length)}, ${frac(sy,points.length)})`}}
function centroidData(v,P){let A=signedArea2(v), sx=0,sy=0; for(let i=0;i<v.length;i++){let p=v[i],q=v[(i+1)%v.length],d=det(p,q); sx+=(p[0]+q[0])*d; sy+=(p[1]+q[1])*d} let area={point:[sx/(3*A),sy/(3*A)],text:`(${frac(sx,3*A)}, ${frac(sy,3*A)})`}; let all=avgFrac(P.all), boundary=avgFrac(P.bd), interior=P.inn.length?avgFrac(P.inn):null; return {area,all,boundary,interior}}
function centroidText(c){return `Area centroid: ${c.area.text}<br>Lattice-point centroid: ${c.all.text}<br>Boundary lattice centroid: ${c.boundary.text}<br>${c.interior?`Interior lattice centroid: ${c.interior.text}`:'Interior lattice centroid: undefined'}`}
function kvTable(rows){return `<div class="kv-table">${rows.map(r=>`<div class="kv-name">${r[0]}</div><div class="kv-value">${r[1]}</div>`).join('')}</div>`}
function detail(title,body){return `<details class="formula"><summary>${title}</summary><div class="body">${body}</div></details>`}
function mathInline(x){return `\\(${x}\\)`}
function hodgeDiamond(rho){let rows=[['1'],['0','0'],['0',String(rho),'0'],['0','0'],['1']]; return `<div class="hodge-diamond" aria-label="Hodge diamond">${rows.map(r=>`<div class="hodge-row" style="--cols:${r.length}">${r.map(c=>`<span>${c}</span>`).join('')}</div>`).join('')}</div>`}
function hodgeDiamondForSurface(s){return s.smooth?hodgeDiamond(s.V-2):`<p class="subtle">Hodge diamond is displayed only for smooth complete toric surfaces. This polygon has singular normal-cone multiplicities ${s.mm.join(', ')}.</p>`}
function hodgeDiamondForFanSummary(fs){return fs.smooth?hodgeDiamond(fs.picardRank):`<p class="subtle">No Hodge diamond is displayed here because the modified fan is still singular.</p>`}
function squareFreePart(n){let q=1,r=Math.abs(n); for(let p=2;p*p<=r;p++)while(r%(p*p)===0){q*=p;r/=p*p} return {q,r}}
function radicalLatex(q,r,imag=false){let core=r===1?'':`\\sqrt{${r}}`; if(imag)core='i'+core; if(!core)core='1'; return (q===1?core:`${q}${core}`)}
function fracLatexInt(n,d=1){return fracLatex(fracObj(n,d))}
function ehrhartRootText(s){let D=s.B*s.B-8*s.Vol, den=2*s.Vol; if(D===0)return mathInline(`k=${fracLatexInt(-s.B,den)}`); let sf=squareFreePart(D), q=sf.q, r=sf.r; if(D>0&&r===1)return mathInline(`k=${fracLatexInt(-s.B-q,den)},\\ ${fracLatexInt(-s.B+q,den)}`); let g=gcd(gcd(s.B,q),den), base=-s.B/g, coef=q/g, d=den/g, term=radicalLatex(coef,r,D<0), num=base===0?`\\pm ${term}`:`${base}\\pm ${term}`; return d===1?mathInline(`k=${num}`):mathInline(`k=\\frac{${num}}{${d}}`)}
function hStarSymmetryText(s){let h1=s.N-3,h2=s.I; return h2===1?`palindromic ${mathInline('(1,'+h1+',1)')}; Gorenstein/reflexive signal after a suitable interior origin`:`not palindromic; ${mathInline('h_2^*='+h2)}`}
function hStarDiagnostics(s){let h=[1,s.N-3,s.I], unimodal=h[0]<=h[1]&&h[1]>=h[2], logConc=h[1]*h[1]>=h[0]*h[2]; return {h,unimodal,logConc,text:`unimodal ${unimodal?'yes':'no'}; log-concave ${logConc?'yes':'no'}`}}
function lowWidthSpectrum(v,extra=3){let s=stats(v), lim=s.lw+extra, dirs=dualDirs(v,lim), rows=[]; for(const m of dirs){let w=width(v,m); if(w<=lim)rows.push({dir:m,w})} rows.sort((a,b)=>a.w-b.w||Math.abs(a.dir[0])+Math.abs(a.dir[1])-Math.abs(b.dir[0])-Math.abs(b.dir[1])||a.dir[0]-b.dir[0]||a.dir[1]-b.dir[1]); let counts=new Map(); rows.forEach(r=>counts.set(r.w,(counts.get(r.w)||0)+1)); return {limit:lim,min:s.lw,minDirs:rows.filter(r=>r.w===s.lw),counts:[...counts.entries()].map(([w,c])=>`${w}:${c}`).join(', '),sample:rows.slice(0,18).map(r=>`(${r.dir[0]},${r.dir[1]})→${r.w}`).join('; ')}}
function widthSpectrumText(v){let ws=lowWidthSpectrum(v); return `min-width directions ${ws.minDirs.length}; spectrum counts up to ${ws.limit}: ${ws.counts}; sample ${ws.sample||'none'}`}
function oneNodeSeveriText(s){return s.smooth?`${mathInline(`3L^2+2LK+c_2=3\\operatorname{Vol}(P)-2B+V=${3*s.Vol-2*s.B+s.V}`)} <span class="subtle">(valid as the universal one-node count only under the usual smooth and sufficiently ample transversality hypotheses)</span>`:'not displayed: the universal node-polynomial formula is only used here for smooth toric surfaces'}
function pointedDualDataForOrigin(v,origin){if(!origin)return null; let Q=v.map(p=>[p[0]-origin[0],p[1]-origin[1]]), Ns=normals(Q), hs=Ns.map(n=>Math.max(...Q.map(p=>dot(n,p)))); if(hs.some(h=>h<=0))return null; let idx=hs.reduce((a,b)=>lcm(a,b),1), integral=Ns.every((n,i)=>n[0]%hs[i]===0&&n[1]%hs[i]===0), raw=integral?Ns.map((n,i)=>[n[0]/hs[i],n[1]/hs[i]]):Ns.map((n,i)=>[n[0]*(idx/hs[i]),n[1]*(idx/hs[i])]); raw=cyc(hull(raw)); let prim=primitivePolygonData(raw); return {Q,Ns,hs,idx,integral,scale:integral?1:idx,rawPoly:raw,rawContent:prim.content,poly:prim.poly,primitiveReduced:prim.changed,origin}}
function pointedDualData(v){return pointedDualDataForOrigin(v,selectedOrigin)}
function coneQuotientData(a,b){let r=Math.abs(det(a,b)); if(r===1)return {smooth:true,r:1,a:0,type:'smooth',hj:[]}; let m=bezoutVector(a), beta=det(a,b); if(beta<0)m=[-m[0],-m[1]]; let alpha=det(b,m); alpha=((alpha%r)+r)%r; if(alpha===0)alpha=1; return {smooth:false,r,a:alpha,type:`1/${r}(1,${alpha})`,hj:hjContinuedFraction(r,alpha)}}
function hjContinuedFraction(r,a){let out=[], guard=0; r=Math.abs(r); a=((a%r)+r)%r; if(a===0||r<=1)return out; while(a!==1&&guard++<32){let b=Math.ceil(r/a); out.push(b); [r,a]=[a,b*a-r]} if(r>1)out.push(r); return out}
