function singularityContentData(Q,hs){let widths=edges(Q), rows=[], basket=[], totalT=0; for(let i=0;i<Q.length;i++){let a=Q[i], b=Q[(i+1)%Q.length], ell=widths[i], h=hs[i], n=Math.floor(ell/h), rho=ell-n*h, q=coneQuotientData(a,b), res=residualSubcone(a,b,ell,h,n,rho), rq=res?coneQuotientData(res.a,res.b):null; totalT+=n; rows.push({i,ell,h,n,rho,q,residual:res,residualQ:rq}); if(rho>0)basket.push({i,rho,q:rq,residual:res})} return {rows,basket,totalT}}
function singularityContentText(sc,diagnostic=false){let basket=sc.basket.length?sc.basket.map(x=>`E${x.i+1}: ${x.q.type}${x.q.hj.length?`, HJ [${x.q.hj.join(',')}]`:''}`).join('; '):'empty'; return `${diagnostic?'diagnostic ':''}T-count ${sc.totalT}; residual basket ${basket}`}
function singularityContentTable(sc){return `<table class="small-table"><thead><tr><th>edge</th><th>width</th><th>local index</th><th>T-count</th><th>residue</th><th>original quotient</th><th>residual quotient</th><th>HJ chain</th></tr></thead><tbody>${sc.rows.map(x=>`<tr><td>E${x.i+1}</td><td>${x.ell}</td><td>${x.h}</td><td>${x.n}</td><td>${x.rho}</td><td>${x.q.type}</td><td>${x.residualQ?x.residualQ.type:'empty'}</td><td>${x.residualQ?(x.residualQ.hj.join(', ')||'smooth'):'empty'}</td></tr>`).join('')}</tbody></table>`}
function coneDiscrepancyData(a,b){let chain=smoothConeChain(a,b), vals=[]; for(let i=1;i<chain.length-1;i++){let disc=localDiscrepancy(a,b,chain[i]), log=fracAdd(disc,fracObj(1,1)); vals.push({ray:chain[i],discrepancy:disc,logDiscrepancy:log})} let minLog=vals.length?vals.map(x=>x.logDiscrepancy).reduce((u,w)=>fracLeq(u,w)?u:w):fracObj(1,1), minDisc=vals.length?vals.map(x=>x.discrepancy).reduce((u,w)=>fracLeq(u,w)?u:w):fracObj(0,1); return {chain,vals,minLog,minDisc,canonical:fracSign(minDisc)>=0,terminal:vals.length===0||vals.every(x=>fracSign(x.discrepancy)>0),logTerminal:fracSign(minLog)>0}}
function residualDiscrepancyData(sc){let vals=[]; for(const r of sc.rows)if(r.residual){let d=coneDiscrepancyData(r.residual.a,r.residual.b); vals.push({edge:r.i+1,...d})} let minLog=vals.length?vals.map(x=>x.minLog).reduce((u,w)=>fracLeq(u,w)?u:w):fracObj(1,1), minDisc=vals.length?vals.map(x=>x.minDisc).reduce((u,w)=>fracLeq(u,w)?u:w):fracObj(0,1); return {vals,minLog,minDisc,canonical:fracSign(minDisc)>=0,terminal:vals.every(x=>x.terminal),logTerminal:fracSign(minLog)>0}}
function residualHJGraphText(sc){return sc.basket.length?sc.basket.map(x=>`E${x.i+1}: [${x.q.hj.join('-')||'smooth'}]`).join('; '):'empty'}
function mutationFingerprint(sc,idx,dual=null){let basket=sc.basket.map(x=>x.q.type).join('|')||'empty', dualKey=dual?`dual:${stats(dual.poly).Vol},${stats(dual.poly).B},${stats(dual.poly).I}`:'dual:none'; return `T${sc.totalT};idx${idx};B{${basket}};${dualKey}`}
function dualPolygonSection(s,v){let d=pointedDualData(v); if(!d)return `<div class="card"><h3>Dual polygon search</h3><p class="subtle">Choose an interior lattice point to form the pointed dual polygon.</p></div>`; let st=stats(d.poly), title=d.primitiveReduced?`${d.integral?'integral':'least-integral scaled'} dual, divided by primitive content ${d.rawContent}`:(d.integral?'primitive integral dual lattice polygon':`${d.idx}-scaled primitive dual lattice polygon`), cP=centroidData(v,latticePoints(v)), cD=centroidData(d.poly,latticePoints(d.poly)), mah=s.Vol*st.Vol; return `<div class="card dual-card"><h3>Dual polygon search</h3>${sectionIntro('The panel uses the currently selected black interior point. Rational polar duals are first scaled to the least integral polygon, then the primitive lattice polygon is displayed and searched.') }<div class="figure-tools">${copyButton(d.poly,'Copy primitive dual vertices')}</div><div class="figure-box">${svgPolygon(d.poly,[],{large:false})}</div>${kvTable([['Displayed object',title],['Selected origin',`(${selectedOrigin[0]},${selectedOrigin[1]})`],['Facet distances of shifted polygon',d.hs.join(', ')],['Integral scale before primitive reduction',d.scale],['Primitive reduction factor',d.rawContent],['Primitive dual stats',`Vol=${st.Vol}, B=${st.B}, I=${st.I}, N=${st.N}`],['Normalized Mahler proxy',`${s.Vol} × ${st.Vol} = ${mah}`],['Barycenter / Futaki proxy',`P area centroid ${cP.area.text}; dual area centroid ${cD.area.text}`],['Reflexive for this origin',d.hs.every(h=>h===1)?'yes':'no']])}<div id="dual-match" class="neighbor-match"><span class="empty">Searching database matches...</span></div></div>`}
async function computeDualSearch(v,root=document){let box=root.querySelector('#dual-match'); if(!box)return; let d=pointedDualData(v); if(!d){box.innerHTML='<span class="empty">No pointed dual is available.</span>';return} let hits=await findEquivalent(d.poly,12); let raw=hits.reduce((s,r)=>s+(r.equivRows?.length||1),0); box.innerHTML=hits.length?`Database match(es) for primitive dual: ${formatMatchLinks(hits)} <span class="subtle">(${hits.length} merged from ${raw} record(s))</span>`:'<span class="empty">No database match for the displayed primitive dual lattice polygon.</span>'; attachOpenLinks(box); renderMath(box)}
function primitivePolygonSection(s,v){let pd=primitivePolygonData(v); if(!pd.changed)return ''; let st=stats(pd.poly); return `<div class="card primitive-card"><h3>Primitive polygon search</h3>${sectionIntro('The current polygon is a lattice dilation after translation. This panel displays the associated primitive polygon and searches it separately.') }<div class="figure-tools">${copyButton(pd.poly,'Copy primitive vertices')}</div><div class="figure-box">${svgPolygon(pd.poly,[],{large:false})}</div>${kvTable([['Dilation factor removed',pd.content],['Anchor vertex before division',`(${pd.anchor[0]},${pd.anchor[1]})`],['Primitive polygon stats',`Vol=${st.Vol}, B=${st.B}, I=${st.I}, N=${st.N}`]])}<div id="primitive-match" class="neighbor-match"><span class="empty">Searching database matches...</span></div></div>`}
