function wallRelationRows(Ns){let n=Ns.length, rows=[], degs=antiCanonicalIntersections(Ns); for(let i=0;i<n;i++){let a=Ns[(i-1+n)%n], b=Ns[i], c=Ns[(i+1)%n], A=det(b,c), B=det(c,a), C=det(a,b), g=gcd(gcd(A,B),C)||1, ia=((i-1+n)%n)+1, ib=i+1, ic=((i+1)%n)+1; A/=g;B/=g;C/=g; rows.push(`<tr><td>${mathInline('D_'+ib)}</td><td>${mathInline(`${A}\\nu_{${ia}}+${B}\\nu_{${ib}}+${C}\\nu_{${ic}}=0`)}</td><td>${mathInline(`(-K)\\cdot D_${ib}=${fracLatex(degs[i])}`)}</td></tr>`)} return `<table class="small-table"><thead><tr><th>curve</th><th>local wall relation</th><th>anti-canonical degree</th></tr></thead><tbody>${rows.join('')}</tbody></table>`}
