async function computeAdjointMatches(v,root=document){let tower=adjointTower(v); for(const t of tower.filter(x=>x.level>=1)){let el=root.querySelector(`[data-adjoint-level="${t.level}"]`); if(!el)continue; let m=await findEquivalent(t.vertices,12); el.innerHTML=m.length?formatMatchLinks(m):'<span class="empty">No database match.</span>'; attachOpenLinks(el); await pause()}}
