function computeMirrorPeriod(v,root=document){let out=root.querySelector('#curve-compute-result'), kind=root.querySelector('#period-support')?.value||'all', K=readOrder(root,16,1), steps=supportPointsForPeriod(v,kind), res=constantTermPeriod(steps,K), red=reducePeriodByStride(res.coeff), shown=Math.min(K,red.coeff.length-1), sub=red.stride>1?`<p class="small-note">Only powers divisible by ${red.stride} are nonzero in the computed range, so the displayed series uses the substitution ${mathInline(`z^{${red.stride}}\\mapsto z`)}.</p>`:''; out.innerHTML=`<h4>Classical constant-term period</h4><p>${mathInline(`\\Phi(z)=\\sum_{n=0}^{${shown}}\\operatorname{CT}(f^{${red.stride>1?`${red.stride}n`:'n'}})z^n=${bigSeriesLatex(red.coeff,'z',shown)}+O(z^{${shown+1}})`)}</p>${sub}<details class="formula"><summary>Nonzero coefficient rows</summary>${periodTable(red.coeff,red.stride)}</details><p class="subtle">Computed through original order ${res.coeff.length-1}; state count at last step: ${res.states.toLocaleString()}.</p>`; renderMath(out)}
function factBig(k){let z=1n; for(let i=2n;i<=BigInt(k);i++)z*=i; return z}
