function brSub(a,b){return br(a.n*b.d-b.n*a.d,a.d*b.d)}
function brMul(a,b){return br(a.n*b.n,a.d*b.d)}
function brDiv(a,b){return br(a.n*b.d,a.d*b.n)}
function brNeg(a){return{n:-a.n,d:a.d}}
function brZero(a){return a.n===0n}
