function nullVectorBigInt(mat){if(!mat.length)return null; let rows=mat.length, cols=mat[0].length, A=mat.map(r=>r.map(x=>br(x))), piv=[], rr=0; for(let c=0;c<cols&&rr<rows;c++){let p=-1; for(let i=rr;i<rows;i++)if(!brZero(A[i][c])){p=i;break} if(p<0)continue; [A[rr],A[p]]=[A[p],A[rr]]; let pv=A[rr][c]; for(let j=c;j<cols;j++)A[rr][j]=brDiv(A[rr][j],pv); for(let i=0;i<rows;i++)if(i!==rr&&!brZero(A[i][c])){let f=A[i][c]; for(let j=c;j<cols;j++)A[i][j]=brSub(A[i][j],brMul(f,A[rr][j]))} piv.push(c); rr++} if(piv.length===cols)return null; let free=cols-1; while(piv.includes(free))free--; let x=Array(cols).fill(null).map(()=>br(0)); x[free]=br(1); piv.forEach((pc,i)=>{x[pc]=brNeg(A[i][free])}); let den=1n; x.forEach(a=>den=lcmBig(den,a.d)); let vec=x.map(a=>a.n*(den/a.d)); let g=0n; vec.forEach(c=>{if(c)g=g?gcdBig(g,c):c<0n?-c:c}); if(g)vec=vec.map(c=>c/g); let first=vec.find(c=>c!==0n); if(first&&first<0n)vec=vec.map(c=>-c); return vec}
