function guessThetaOperator(coeff,maxR=null,maxD=4){let N=coeff.length-1, degrees=[]; for(let d of [1,2,3,4])if(d<=maxD)degrees.push(d); for(const D of degrees){let rmax=Math.floor((N+1)/(D+1))-1; if(maxR!==null)rmax=Math.min(rmax,maxR); for(let R=1;R<=Math.max(0,rmax);R++){let cols=(R+1)*(D+1); if(N+1<cols)continue; let mat=[]; for(let n=0;n<=N;n++){let row=[]; for(let j=0;j<=R;j++)for(let d=0;d<=D;d++){let val=0n; if(n>=j){let m=BigInt(n-j); val=coeff[n-j]*(m**BigInt(d))} row.push(val)} mat.push(row)} let vec=null; try{vec=nullVectorBigInt(mat)}catch(e){vec=null} if(!vec)continue; let ok=true; for(let n=0;n<=N;n++){let sum=0n, c=0; for(let j=0;j<=R;j++)for(let d=0;d<=D;d++,c++)if(n>=j)sum+=vec[c]*coeff[n-j]*(BigInt(n-j)**BigInt(d)); if(sum!==0n){ok=false;break}} if(ok&&vec.some(Boolean)){return{R,D,vec}}}} return null}
