function polyRootsSmallNum(coefs){while(coefs.length&&Math.abs(coefs.at(-1))<1e-10)coefs.pop(); let d=coefs.length-1; if(d<0)return[]; if(d===1)return[-coefs[0]/coefs[1]]; if(d===2){let [c,b,a]=coefs, D=b*b-4*a*c; if(D>=-1e-10){D=Math.max(0,D); return[(-b-Math.sqrt(D))/(2*a),(-b+Math.sqrt(D))/(2*a)]}} return[]}
function divisorsInt(n){n=Math.abs(Math.round(n)); if(n===0)return[0]; let out=[]; for(let i=1;i*i<=n;i++)if(n%i===0){out.push(i); if(i*i!==n)out.push(n/i)} return out}
