function neighborSection(){return `<div class="card"><h3>Single-lattice-point neighbours</h3>${sectionIntro('Operations changing the full lattice-point set by exactly one point. For each operation, the new set must again be exactly all lattice points of its convex hull.') }<div class="neighbor-toolbar"><label>Add-point search radius <input id="neighbor-radius" type="number" min="1" max="10" value="3"></label><button id="compute-neighbors" type="button">Build neighbour operations</button></div><div id="neighbor-ops" class="neighbor-ops"></div></div>`}
