function computeNeighbors(v,root=document){let out=root.querySelector('#neighbor-ops'); out.innerHTML='<p class="empty">Building exact one-point operation list…</p>'; let radius=Math.max(1,Math.min(10,+(root.querySelector('#neighbor-radius')?.value||3))), box=bbox(v), baseAll=latticePoints(v).all, baseKeys=pointKeySet(baseAll); let removals=[]; for(const p of baseAll){let newSet=baseAll.filter(q=>q[0]!==p[0]||q[1]!==p[1]), h=exactConvexLatticeSet(newSet); if(h)removals.push({kind:'remove',label:`remove lattice point (${p[0]},${p[1]})`,point:p,v:h,all:newSet})} let adds=[]; for(let x=box.minX-radius;x<=box.maxX+radius;x++)for(let y=box.minY-radius;y<=box.maxY+radius;y++){let p=[x,y], key=p.join(','); if(baseKeys.has(key))continue; let newSet=baseAll.concat([p]), h=exactConvexLatticeSet(newSet); if(h)adds.push({kind:'add',label:`add lattice point (${x},${y})`,point:p,v:h,all:newSet})} NEIGHBOR_TASKS=removals.concat(adds).slice(0,220); let truncated=removals.length+adds.length>NEIGHBOR_TASKS.length; out.innerHTML=`<p class="small-note">${removals.length} deletion(s), ${adds.length} addition(s) within radius ${radius}. The test uses the full lattice-point set, not only hull vertices.${truncated?' Showing first '+NEIGHBOR_TASKS.length+'.':''}</p><div class="neighbor-list">${NEIGHBOR_TASKS.map((t,i)=>`<div class="neighbor-card"><div class="neighbor-title"><strong>${t.label}</strong><span>${t.kind==='remove'?'red point is deleted':'green point is added'}</span></div><div class="figure-tools">${copyButton(t.v)}</div>${svgNeighbor(v,t.v,t.point,t.kind,baseAll,t.all)}<button type="button" data-neighbor-search="${i}">Search database matches</button><div class="neighbor-match" id="neighbor-match-${i}"></div></div>`).join('')}</div>`; out.querySelectorAll('[data-neighbor-search]').forEach(b=>b.onclick=()=>searchNeighbor(+b.dataset.neighborSearch)); attachCopyButtons(out)}
