function makeGrid(){DRAW_GRID_N=Math.max(4,Math.min(40,+$('#grid-size').value||13)); DRAW_SELECTED=new Set(); let n=DRAW_GRID_N, host=$('#point-grid'), size=Math.max(360,Math.min(760,26*n+72)), pad=34, step=(size-2*pad)/(n-1), hitR=Math.max(11,Math.min(20,step*.42)), origin=Math.floor(n/2), coord=i=>i-origin, Xc=c=>pad+(c+origin)*step, Yc=c=>size-pad-(c+origin)*step; let lines=''; for(let i=0;i<n;i++){let c=coord(i), cls=c===0?'axisline':'gridline'; lines+=`<line class="${cls}" x1="${Xc(c)}" y1="${Yc(coord(0))}" x2="${Xc(c)}" y2="${Yc(coord(n-1))}"/><line class="${cls}" x1="${Xc(coord(0))}" y1="${Yc(c)}" x2="${Xc(coord(n-1))}" y2="${Yc(c)}"/>`} let pts='', hits=''; for(let j=0;j<n;j++)for(let i=0;i<n;i++){let x=coord(i), y=coord(j), cx=Xc(x), cy=Yc(y), key=`${x},${y}`; pts+=`<circle class="grid-point" data-p="${key}" cx="${cx}" cy="${cy}" r="4.8"><title>(${x},${y})</title></circle>`; hits+=`<circle class="grid-hit" data-p="${key}" cx="${cx}" cy="${cy}" r="${hitR}" aria-label="lattice point (${x},${y})"/>`} host.innerHTML=`<svg class="draw-grid-svg" viewBox="0 0 ${size} ${size}" role="img" aria-label="centered lattice point drawing grid">${lines}<g id="draw-hull-layer"></g><g id="draw-point-layer">${pts}</g><g id="draw-hit-layer">${hits}</g></svg>`; host.dataset.ready='1'; host.querySelectorAll('.grid-hit,.grid-point').forEach(c=>{c.onpointerdown=e=>{e.preventDefault(); toggleGridPoint(c.dataset.p)}}); updateSelectedHull()}
function selectedGridPoints(){return [...DRAW_SELECTED].map(s=>s.split(',').map(Number))}
function updateSelectedHull(){let P=selectedGridPoints(), out=$('#selected-summary'), layer=$('#draw-hull-layer'); DRAW_AUTO_ORIGIN=null; $$('#point-grid .grid-point').forEach(c=>c.classList.toggle('selected',DRAW_SELECTED.has(c.dataset.p))); if(!layer)return; if(P.length<3){out.textContent=`${P.length} point(s) selected.`; layer.innerHTML=''; return} let h=hull(P), A=area2(h); out.textContent=`${P.length} point(s) selected; current hull has ${h.length} vertices and normalized volume ${A}.`; if(A===0){layer.innerHTML=''; out.textContent+=' Selected points are collinear.'; return} let selectedInterior=P.filter(p=>!onbd(p,h)&&inside(p,h)); let allInterior=latticePoints(h).inn; if(selectedInterior.length===1)DRAW_AUTO_ORIGIN=selectedInterior[0]; else if(allInterior.length===1)DRAW_AUTO_ORIGIN=allInterior[0]; if(DRAW_AUTO_ORIGIN)out.textContent+=` Auto-selected interior point: (${DRAW_AUTO_ORIGIN[0]},${DRAW_AUTO_ORIGIN[1]}).`; let svg=$('.draw-grid-svg'), vb=svg.viewBox.baseVal, n=DRAW_GRID_N, pad=30, origin=Math.floor(n/2), step=(vb.width-2*pad)/(n-1), X=x=>pad+(x+origin)*step, Y=y=>vb.height-pad-(y+origin)*step; layer.innerHTML=`<polygon class="draw-hull" points="${h.map(p=>X(p[0])+','+Y(p[1])).join(' ')}"/>${h.map(p=>`<circle class="draw-hull-vertex" cx="${X(p[0])}" cy="${Y(p[1])}" r="7"><title>hull vertex (${p[0]},${p[1]})</title></circle>`).join('')}${DRAW_AUTO_ORIGIN?`<circle class="draw-auto-origin" cx="${X(DRAW_AUTO_ORIGIN[0])}" cy="${Y(DRAW_AUTO_ORIGIN[1])}" r="8"><title>auto-selected interior point (${DRAW_AUTO_ORIGIN[0]},${DRAW_AUTO_ORIGIN[1]})</title></circle>`:''}`}
function svgTransformComparison(inputHull,targetHull,T,marked=null){let moved=T?inputHull.map(p=>applyAffine(p,T)):inputHull, all=moved.concat(targetHull).concat(marked?[marked]:[]), b=bbox(all), pad=24, maxW=360, maxH=230, sx=maxW/Math.max(1,b.maxX-b.minX+1), sy=maxH/Math.max(1,b.maxY-b.minY+1), sc=Math.min(sx,sy,42), W=(b.maxX-b.minX)*sc+2*pad, H=(b.maxY-b.minY)*sc+2*pad, X=p=>pad+(p[0]-b.minX)*sc, Y=p=>H-pad-(p[1]-b.minY)*sc; return `<svg class="shape-map-svg" width="100%" height="${H}" viewBox="0 0 ${W} ${H}"><polygon class="poly" points="${targetHull.map(p=>X(p)+','+Y(p)).join(' ')}"/><polygon class="mapped-poly" points="${moved.map(p=>X(p)+','+Y(p)).join(' ')}"/>${targetHull.map(p=>`<circle class="vertex" cx="${X(p)}" cy="${Y(p)}" r="4"/>`).join('')}${moved.map(p=>`<circle class="mapped-point" cx="${X(p)}" cy="${Y(p)}" r="2.8"/>`).join('')}${marked?`<circle class="origin" cx="${X(marked)}" cy="${Y(marked)}" r="6"><title>mapped selected interior (${marked[0]},${marked[1]})</title></circle>`:''}</svg>`}
async function renderShapeResults(rows,container,inputHull){container.innerHTML=''; for(const r of rows){let rec=await fetchRecord(r), dv=optDisplay(rec.v).v, T=aglTransform(inputHull,dv), mappedOrigin=DRAW_AUTO_ORIGIN&&T?applyAffine(DRAW_AUTO_ORIGIN,T):null, el=resultElement(r,mappedOrigin), main=el.querySelector('.result-main'); let info=document.createElement('div'); info.className='shape-transform-info'; info.innerHTML=`<div><strong>Affine transform from drawn hull to minimum-square display:</strong> ${transformLatex(T)}<br><span class="subtle">${transformPlain(T)}${mappedOrigin?`; selected interior maps to (${mappedOrigin[0]},${mappedOrigin[1]})`:''}</span></div><div><div class="figure-tools">${copyButton(dv)}</div>${svgTransformComparison(inputHull,dv,T,mappedOrigin)}</div>`; main.insertAdjacentElement('afterend',info); container.appendChild(el); attachCopyButtons(info); await pause()} renderMath(container); if(rows.length===1){let btn=container.querySelector('[data-act="open"]'); if(btn)btn.click()}}
function virtualRowFromPolygon(h){let v=hull(h), s=stats(v), P=latticePoints(v), row=[]; row[MIDX.id]=0; row[MIDX.cno]=0; row[MIDX.off]=0; row[MIDX.Vol]=s.Vol; row[MIDX.V]=s.V; row[MIDX.B]=s.B; row[MIDX.I]=s.I; row[MIDX.N]=s.N; row[MIDX.lw]=s.lw; row[MIDX.box]=s.boxSq; row[MIDX.content]=s.content; row[MIDX.smooth]=s.smooth?1:0; row[MIDX.src]=0; row[MIDX.edge]=s.edge; row[MIDX.prim]=s.primEdges; row[MIDX.maxE]=s.maxEdge; row[MIDX.minE]=s.minEdge; row[MIDX.cent]=centralFromPoints(P.all)?1:0; row[MIDX.mult]=s.mult; row[MIDX.srcCount]=0; row.__virtual=true; row.__vertices=clonePoints(v); row.__virtualTitle='Drawn polygon (not in database)'; return row}
async function renderVirtualShapeResult(h,container){let row=virtualRowFromPolygon(h), dv=optDisplay(h).v, T=aglTransform(h,dv), mappedOrigin=DRAW_AUTO_ORIGIN&&T?applyAffine(DRAW_AUTO_ORIGIN,T):null, el=resultElement(row,mappedOrigin), main=el.querySelector('.result-main'); let info=document.createElement('div'); info.className='shape-transform-info'; info.innerHTML=`<div><strong>No strict database match.</strong> The drawn hull is opened below as a temporary local polygon, so browser-computable invariants are still available.<br><span class="subtle">Display transform: ${transformPlain(T)}${mappedOrigin?`; selected interior maps to (${mappedOrigin[0]},${mappedOrigin[1]})`:''}</span></div><div><div class="figure-tools">${copyButton(dv)}</div>${svgTransformComparison(h,dv,T,mappedOrigin)}</div>`; main.insertAdjacentElement('afterend',info); container.appendChild(el); attachCopyButtons(info); renderMath(container); let btn=container.querySelector('[data-act="open"]'); if(btn)btn.click(); await pause()}
async function relatedShapeCandidates(h){let out=[], seen=new Set(), add=(label,poly)=>{if(!poly||poly.length<3||area2(poly)===0)return; let k=keyOf(poly); if(seen.has(k)||k===keyOf(h))return; seen.add(k); out.push({label,poly})}; let pd=primitivePolygonData(h); if(pd.changed)add(`primitive polygon (factor ${pd.content})`,pd.poly); if(DRAW_AUTO_ORIGIN){let d=pointedDualDataForOrigin(h,DRAW_AUTO_ORIGIN); if(d)add('primitive pointed dual',d.poly)} adjointTower(h).filter(t=>t.level>=1).slice(0,4).forEach(t=>add(`adjoint tower level ${t.level}`,t.vertices)); let P=latticePoints(h), md=minkowskiData(h,P), segs=md.segmentSummands.slice(0,4); segs.forEach((z,i)=>add(`Minkowski segment quotient ${i+1}`,z.quotientVertices)); return out}
async function renderRelatedShapeSearch(h,out){let candidates=await relatedShapeCandidates(h), blocks=[]; for(const c of candidates){let hits=await findEquivalent(c.poly,8), raw=hits.reduce((s,r)=>s+(r.equivRows?.length||1),0); blocks.push(`<div class="neighbor-card"><div class="neighbor-title"><strong>${c.label}</strong><span>${hits.length?`${hits.length} merged / ${raw} raw match(es)`:'no database match'}</span></div><div class="figure-tools">${copyButton(c.poly)}</div>${svgPolygon(c.poly,[],{large:false})}<div class="neighbor-match">${hits.length?formatMatchLinks(hits):'<span class="empty">No database match.</span>'}</div></div>`); await pause()} out.innerHTML=`<p class="empty">No strict match found in the database.</p><p class="small-note">Related database searches were attempted for primitive, dual, adjoint-tower and Minkowski-derived polygons when available.</p>${blocks.length?`<div class="neighbor-list">${blocks.join('')}</div>`:'<p class="empty">No related candidate polygon was available.</p>'}`; attachCopyButtons(out); attachOpenLinks(out); renderMath(out)}
async function shapeSearch(){let P=selectedGridPoints(), h=hull(P), out=$('#shape-result'); if(P.length<3||h.length<3||area2(h)===0){out.innerHTML='<p class="empty">Select at least three non-collinear lattice points.</p>'; return} out.innerHTML='<p class="empty">Searching invariant bucket with exact AGL2Z verification...</p>'; let hits=await findEquivalent(h,50); if(!hits.length){out.innerHTML=`<p class="small-note">No strict database match was found. A temporary local record is opened below; browser-computable invariants are shown there directly.</p><div class="results" id="drawn-local-result"></div>`; await renderVirtualShapeResult(h,out.querySelector('#drawn-local-result')); return} let raw=hits.reduce((s,r)=>s+(r.equivRows?.length||1),0); out.innerHTML=`<p class="small-note">${hits.length} merged match(es) from ${raw} equivalent record(s). ${DRAW_AUTO_ORIGIN?`Auto-selected interior point in the drawn polygon: (${DRAW_AUTO_ORIGIN[0]},${DRAW_AUTO_ORIGIN[1]}).`:''} Each card shows an affine unimodular map from your drawn hull to the stored polygon.</p><div class="results"></div>`; await renderShapeResults(hits,out.querySelector('.results'),h)}

$('#search-form').onsubmit=search; $('#stop-render').onclick=()=>{renderStop=true}; $('#make-grid').onclick=makeGrid; $('#clear-grid').onclick=()=>{DRAW_SELECTED.clear(); DRAW_AUTO_ORIGIN=null; updateSelectedHull(); $('#shape-result').innerHTML=''}; $('#shape-search').onclick=shapeSearch; initDrawGrid(); window.addEventListener('load',load);
